-- =============================================================================
-- Migration 241 — OTA Translations
--
-- Cria uma camada de traduções remotas para permitir correção/ajuste de textos
-- sem publicar novo APK. As strings locais permanecem como fallback offline.
-- =============================================================================

CREATE TABLE IF NOT EXISTS public.app_translations (
  locale      TEXT NOT NULL,
  key         TEXT NOT NULL,
  value       TEXT NOT NULL,
  category    TEXT NOT NULL DEFAULT 'l10n',
  is_active   BOOLEAN NOT NULL DEFAULT TRUE,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_by  UUID REFERENCES auth.users(id) ON DELETE SET NULL,
  PRIMARY KEY (locale, key)
);

CREATE INDEX IF NOT EXISTS idx_app_translations_locale_active
  ON public.app_translations(locale, is_active);

ALTER TABLE public.app_translations ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "app_translations_public_read" ON public.app_translations;
CREATE POLICY "app_translations_public_read" ON public.app_translations
  FOR SELECT TO anon, authenticated
  USING (is_active = TRUE);

DROP POLICY IF EXISTS "app_translations_admin_write" ON public.app_translations;
CREATE POLICY "app_translations_admin_write" ON public.app_translations
  FOR ALL TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid() AND is_team_admin = TRUE
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid() AND is_team_admin = TRUE
    )
  );

CREATE OR REPLACE FUNCTION public.set_app_translations_updated_at()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  NEW.updated_at = NOW();
  NEW.updated_by = auth.uid();
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS app_translations_updated_at ON public.app_translations;
CREATE TRIGGER app_translations_updated_at
  BEFORE UPDATE ON public.app_translations
  FOR EACH ROW EXECUTE FUNCTION public.set_app_translations_updated_at();

CREATE OR REPLACE FUNCTION public.get_app_translations(p_locale TEXT)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  result JSONB := '{}'::jsonb;
  rec RECORD;
BEGIN
  FOR rec IN
    SELECT key, value
    FROM public.app_translations
    WHERE locale = p_locale AND is_active = TRUE
    ORDER BY key
  LOOP
    result := result || jsonb_build_object(rec.key, rec.value);
  END LOOP;
  RETURN result;
END;
$$;

GRANT EXECUTE ON FUNCTION public.get_app_translations(TEXT) TO anon, authenticated;

